#include <iostream>
#include <fstream>
#include <vector>
#include <cmath>
#include <iomanip>
using namespace std;

int main() {
  // Open the input file for reading and the output file for writing
  ifstream in_file("compresie.in");
  ofstream out_file("compresie.out");

  // Read data from file
  int n, m;
  in_file >> n;

  vector<int> A(n);
  for (int i = 0; i < n; i++) {
    in_file >> A[i];
  }

  in_file >> m;
  vector<int> B(m);
  for (int i = 0; i < m; i++) {
    in_file >> B[i];
  }

  int i = 1, j = 1;

  while (i <= n && j <= m) {
    // Check if the elements are equal and skip them
    if (A[i - 1] == B[j - 1]) {
      i++;
      j++;
    // Check if the elements are different, add the smaller one to the next
    // one in the array and set the current one to 0
    } else if (A[i - 1] < B[j - 1]) {
      A[i] += A[i - 1];
      A[i - 1] = 0;
      i++;
    } else {
      B[j] += B[j - 1];
      B[j - 1] = 0;
      j++;
    }
  }

  // Check if we reached the end of the arrays and print the result
  if (i == n + 1 && j == m + 1) {
    int res = 0;
    // Count the number of non-zero elements in one of the arrays
    for (int i = 0; i < n; i++) {
      if (A[i] != 0) {
        res++;
      }
    }
    out_file << res << endl;
  } else {
    // If we didn't reach the end of the arrays that means
    // we couldn't compress them enough
    out_file << -1 << endl;
  }

  // Close the files
  in_file.close();
  out_file.close();

  return 0;
}

import java.io.BufferedWriter;
import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class Compresie {

	private static int calculateMaxLength(int[] A, int[] B) {
		// calculez lungimea maxima a sirului
		int length = 0;
		int sumA = 0, sumB = 0;
		int indexA = 0, indexB = 0;
		boolean okA = true;
		boolean okB = true;

		while (indexA < A.length && indexB < B.length) {
			if (okA) { // adaug la suma elementul din A
				sumA += A[indexA];
			}
			if (okB) { // adaug la suma elementul din B
				sumB += B[indexB];
			}

			if (sumA == sumB) { 
				// daca sumele sunt egale, maresc lungimea sirului, trec la urmatoarele elemente
				length++;
				indexA++;
				indexB++;
				sumA = 0;
				sumB = 0;
				okA = true;
				okB = true;

			} else if (sumA < sumB) { 
				// daca suma din A este mai mica trec la urmatorul element pentru a-l adauga
				okA = true;
				okB = false;
				indexA++;

			} else {
				// daca suma din B este mai mica trec la urmatorul element pentru a-l adauga
				okB = true;
				okA = false;
				indexB++;
			}
		}
		if (indexA != A.length || indexB != B.length) {
			// daca nu s-au parcurs ambele siruri pana la sfarsit, inseamna ca nu exista solutie
			return -1;
		}

		// returnez lungimea
		return length;
	}

	public static void main(String[] args) {
		try {
			// citesc datele de intrare din fisier
			Scanner scanner = new Scanner(new File("compresie.in"));
			int n = scanner.nextInt();

			int[] A = new int[n];
			for (int i = 0; i < n; i++) {
				A[i] = scanner.nextInt();
			}
			int m = scanner.nextInt();

			int[] B = new int[m];
			for (int i = 0; i < m; i++) {
				B[i] = scanner.nextInt();
			}
			scanner.close();

			// lungimea maxima a sirului rezultat
			int maxLength = calculateMaxLength(A, B);

			// rezultatul in fisierul de iesire
			BufferedWriter writer = new BufferedWriter(new FileWriter("compresie.out"));
			writer.write(String.valueOf(maxLength));
			writer.close();

		} catch (IOException e) {
			e.printStackTrace();
		}
	}
}
